using ModelContextProtocol.Server;
using System.Text.Json;

[McpServerResource(Name = "config://app",
    Description = "Returns application configuration data")]
public class ConfigResource
{
    private static readonly Dictionary<string, object> _config = new()
    {
        ["appName"] = "McpHttpServer",
        ["version"] = "1.0.0",
        ["environment"] = "production",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true
        }
    };

    [ResourceMethod]
    public static string GetConfig()
    {
        return JsonSerializer.Serialize(_config, new JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class GreetingTool
{
    [McpServerTool(Name = "greet"), Description("Greets a user by name")]
    public static string Greet(
        [Description("The name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the MCP HTTP server.";
    }
}

