using System.Reflection;

var asm = Assembly.LoadFrom(Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/modelcontextprotocol/1.3.0/lib/net10.0/ModelContextProtocol.dll"));

foreach (var t in asm.GetExportedTypes()
    .Where(t => t.Name.Contains("Resource"))
    .OrderBy(t => t.FullName))
{
    Console.WriteLine(t.FullName);
    if (t.Name.EndsWith("Attribute"))
    {
        foreach (var p in t.GetProperties())
            Console.WriteLine($"  prop: {p.Name} ({p.PropertyType.Name})");
        foreach (var c in t.GetConstructors())
            Console.WriteLine($"  ctor: ({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
EOF
