arguments.new_str:
using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public class ConfigResource
{
    private static readonly Dictionary<string, object> Config = new()
    {
        ["appName"] = "McpHttpServer",
        ["version"] = "1.0.0",
        ["environment"] = "production",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true
        }
    };

    [McpServerResource(UriTemplate = "config://app", Name = "app-config",
        Title = "Application Configuration", MimeType = "application/json")]
    [Description("Returns application configuration data")]
    public static string GetConfig()
    {
        return JsonSerializer.Serialize(Config, new JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

